import React from 'react';
import styles from './price.module.css';

interface PriceProps {
    shipping: tex
}

const Price = ({ shipping }) => {
  return (
    <div className={styles.wrapper_price}>
        <div className={styles.subtotal}>
            <h6 className={styles.title}>Subtotal</h6>

        </div>
        <div className={styles.shipping_price}>
        <h6 className={styles.title}>Shipping</h6>
        <p className={styles.shipping}>Calculated at the next step</p>

        </div>
        <div className={styles.divider} />
        <div className={styles.total}>
        <h6 className={styles.title}>Total</h6>

        </div>

    </div>
  )
}

export default Price;
